    if (agBtnEl) { agBtnEl.textContent='⏹ Parar (F8)'; agBtnEl.dataset.on='true'; }
    // Auto-start autosell — usa flag no localStorage para evitar referencia prematura
    agAutoSellPendingStart = true;
    // sync mini btn
    var _sh3 = document.getElementById('ag-panel-host') && document.getElementById('ag-panel-host').shadowRoot;
    var _mb = _sh3 && _sh3.getElementById('ag-mini-btn');
    if (_mb) { _mb.dataset.on='true'; _mb.innerHTML='&#9646;&#9646; Parar'; }
