      const inpStyle = 'width:100%;box-sizing:border-box;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.16);border-radius:4px;color:#d4d8e2;font-size:11px;padding:3px 6px;outline:none;font-family:inherit;margin-top:2px';
