    var drag = null;
    var didDrag = false;
    var dz = $('ag-drag-zone');
    dz.addEventListener('pointerdown', function(e) {
      e.stopPropagation(); e.stopImmediatePropagation();
      var r = host.getBoundingClientRect();
      drag = { dx: e.clientX - r.left, dy: e.clientY - r.top };
      didDrag = false;
      dz.setPointerCapture(e.pointerId);
    });
    dz.addEventListener('pointermove', function(e) {
      if (!drag) return;
      e.stopPropagation(); e.stopImmediatePropagation();
      var dx2 = e.clientX - (host.getBoundingClientRect().left + drag.dx);
      var dy2 = e.clientY - (host.getBoundingClientRect().top  + drag.dy);
      if (Math.abs(dx2) > 4 || Math.abs(dy2) > 4) {
        didDrag = true;
        host.style.right = 'auto'; host.style.bottom = 'auto';
        host.style.left = (e.clientX - drag.dx) + 'px';
        host.style.top  = (e.clientY - drag.dy) + 'px';
      }
    });
    dz.addEventListener('pointerup', function(e) {
      e.stopPropagation(); drag = null;
      if (didDrag) setTimeout(function(){ didDrag = false; }, 200);
    });
    // Mini drag
    var mv = $('ag-mini-view');
