  // ── Auto-updater: detecta nova versão e recarrega automaticamente ───────────
  // O proxy serve o novo game.js — o farmer detecta a diferença e dá F5 sozinho
  (function agAutoUpdate() {
    var CHECK_INTERVAL = 60 * 1000; // checar a cada 60s
    var CURRENT = AG_VERSION;

    function checkVersion() {
      fetch('/game.js', { method: 'HEAD', cache: 'no-store' })
        .then(function(r) {
          // Pegar ETag ou Last-Modified para comparar sem baixar o arquivo inteiro
          var etag    = r.headers.get('ETag') || '';
          var lastMod = r.headers.get('Last-Modified') || '';
          var sig     = etag || lastMod;
          if (!sig) return; // servidor não suporta — sem checagem
          var stored = sessionStorage.getItem('ag_game_sig');
          if (!stored) { sessionStorage.setItem('ag_game_sig', sig); return; }
          if (stored !== sig) {
            AG_LOG.warn('[AutoUpdate] Nova versão detectada (' + stored + ' → ' + sig + ') — recarregando em 3s…');
            agPersistLog('WARN', '[AutoUpdate]', ['Nova versão: ' + sig + ' — F5 automático']);
            sessionStorage.setItem('ag_game_sig', sig);
            setTimeout(function() { location.reload(); }, 3000);
          }
        })
        .catch(function() {}); // silencia erros de rede
    }

    // Salvar assinatura inicial
    fetch('/game.js', { method: 'HEAD', cache: 'no-store' })
      .then(function(r) {
        var sig = r.headers.get('ETag') || r.headers.get('Last-Modified') || '';
        if (sig) sessionStorage.setItem('ag_game_sig', sig);
      }).catch(function() {});

    setInterval(checkVersion, CHECK_INTERVAL);
    console.info('[AG AutoUpdate] Monitorando versão a cada ' + (CHECK_INTERVAL/1000) + 's | atual: ' + CURRENT);
  })();

